var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"이쪽으로 휘두른다! 피해!","JPN":"こっちに振り回すぞ！　避けろ！","ENG":"It's attacking this way! Take cover!","TWN":"朝這邊揮！躲開！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"안돼… 이미 늦었어!","JPN":"ダメだ……もう遅い！","ENG":"Shoot...! It's too late for me...!","TWN":"沒辦法…來不及！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"대장님?","JPN":"隊長？","ENG":"Captain?","TWN":"隊長？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"내가 막고 있을 테니…! 어서… 도망쳐!","JPN":"私が止めておく……！　早く……逃げろ！","ENG":"I'll cover you...! So... RUN!","TWN":"我來拖住它…！快…快跑！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"네… 네!","JPN":"は……はい！","ENG":"Y-yes, ma'am!","TWN":"好… 好！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"큭…! 더 이상은…!","JPN":"くっ……！　これ以上は……！","ENG":"Kgh...! I can't hold it off any longer...!","TWN":"咳…！不准…！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저격조! 지금이다!","JPN":"狙撃組！　今だ！","ENG":"Snipers! Now!","TWN":"狙擊組！就是現在！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"명중 확인! 머리를 정확하게 관통했습니다!","JPN":"命中を確認！　正確に頭を貫通しました！","ENG":"Hit confirmed! Right between its eyes!","TWN":"確認命中！準確貫穿頭部！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"대장, 괜찮나?","JPN":"隊長、大丈夫か？","ENG":"Captain, are you good?","TWN":"隊長，你還好嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하… 아슬아슬했어.","JPN":"は……ギリギリだった。","ENG":"*Sigh...* That was a close one.","TWN":"哈…差點小命不保。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"뒤, 뒤를 조심하십쇼, 지휘관님!","JPN":"う、後ろに気をつけてください、指揮官！","ENG":"B-behind you, Sir!","TWN":"後面，小心後面，指揮官！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"괜찮아?","JPN":"大丈夫？","ENG":"You all right?","TWN":"還好嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"목숨을 구해주자마자 또 목숨빚을 지는군.","JPN":"命を助けた途端、また借りができたな。","ENG":"Just when I thought my debt was paid...","TWN":"才剛救你一命，結果又欠你一命。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런 거 피곤하게 일일이 계산하지 마, 빨리 늙으니까.","JPN":"疲れるからそんなのいちいち計算しないで、早く老けるよ。","ENG":"Stop worrying about debts to pay. It'll make you age faster.","TWN":"別這麼愛計較，老得快。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저건 아직도 멀쩡하네.","JPN":"あれはまだびくともしないね。","ENG":"That thing's barely hurt.","TWN":"它還好好的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"분명 쐐기 대포 두 발이 적중하는 걸 봤다.","JPN":"くさび大砲二発が的中したのは確かだ。","ENG":"I saw it get hit with two Ironshot Cannon shots.","TWN":"我明明看到二枚楔子大砲打中它。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 놈은 전혀 타격을 입었다는 반응이 아니군.","JPN":"だが、やつはまったくダメージを受けているように見えないな。","ENG":"But it's acting as if we didn't even make a scratch on it...","TWN":"這傢伙卻完全沒反應。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"다행히 강한 힘에 비해 그리 민첩하진 않아.","JPN":"幸い、強い力に比べてそこまで素早くはない。","ENG":"At least it's not as fast as it is powerful.","TWN":"幸好它雖然力氣大，動作卻沒那麼敏捷。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"자기 힘을 어떻게 쓰는지 모르는 게 아닌가 싶을 정도로.","JPN":"自分の力をどう使えばいいか知らないんじゃないかってくらい。","ENG":"It's almost as if it doesn't know how to use its power...","TWN":"甚至不知道如何使用自己的力量。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇다면 시도해 볼 방법이 남아 있다는 뜻이군.","JPN":"なら、試してみる方法が残ってるということだな。","ENG":"Then that means we might have a way to win.","TWN":"那就表示還有辦法。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…방법?","JPN":"……方法？","ENG":"A way to win?","TWN":"…辦法？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"와트. 준비는 어떻게 되고 있지?","JPN":"ワット。準備の方はどうだ？","ENG":"Watt, how are the preparations going?","TWN":"華特，準備得如何？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"폭탄 설치는 거의 끝났습니다!","JPN":"爆弾の設置はほぼ終わりました！","ENG":"The bombs are almost good to go!","TWN":"炸彈就快安裝完畢！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"망할, 이 지긋지긋한 갱도 열차를 다시 타보게 될 줄은 몰랐군요.","JPN":"くそ、またこのうんざりする坑道列車に乗ることになるなんて思いませんでした。","ENG":"Ugh... Who would've thought I'd be riding this godawful train again...","TWN":"可惡，沒想到竟然還會搭上這討厭的坑道火車。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고생했다. 내가 신호할 때까지 대기하도록.","JPN":"ご苦労だったな。合図するまで待機してくれ。","ENG":"Great work. Wait until I give the signal.","TWN":"辛苦了，等我的訊號。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"알겠습니다! 걱정마십쇼!","JPN":"わかりました！　心配しないでください！","ENG":"Roger that! Don't worry about us!","TWN":"好的！請放心！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"무슨 계획을 세워 둔 거야?","JPN":"何をするつもり？","ENG":"What are you planning?","TWN":"你的計畫是什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이곳에 오는 길에 오래전 폐쇄된 지하 광산을 봐 뒀다.","JPN":"ここに来る途中、昔閉鎖された地下鉱山を見た。","ENG":"I found a closed-off mine on our way over here.","TWN":"我來這裡的路上，有看到很久之前封閉的地下礦山。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"처치는 힘들더라도, 한동안 생매장시켜 버리는 건 가능하겠지.\xA0","JPN":"倒すことはできなくても、しばらく生き埋めにしておくことはできるだろう。\xA0","ENG":"We might not be able to kill it, but we might be able to bury it down there.\xA0","TWN":"雖然不好處理，但應該可以活埋一陣子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지금으로서는 최선이겠네. 우리까지 생매장 당할 수 있다는 것만 빼면 말이야.","JPN":"現状ではそれがベストだね。私たちまで生き埋めになる可能性があることを除けば。","ENG":"That might be our best shot. Except for the fact that we might get buried down there with it.","TWN":"排除我們也會被活埋的可能性，這應該是目前最好的辦法。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"유인은 할 수 있겠나?","JPN":"おびき寄せられるか？","ENG":"Do you think you can lure it in?","TWN":"你可以引它過來嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"대장이 열심히 싸우는 동안 한눈 팔고 있었던 거야?","JPN":"隊長が一生懸命戦ってるところを見なかったの？","ENG":"What? You weren't paying attention while your Captain was doing all the hard work?","TWN":"少小看我的實力。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"좋아. 뒤에 타라. 허밋의 속도라면 저 놈을 따돌리고 빠져나올 수 있어.","JPN":"よし。後ろに乗れ。ハーミットの速度ならあいつをまいて抜け出せる。","ENG":"Okay. Jump on. With Hermit's speed, we might be able to outrun it.","TWN":"好，你坐後面。照赫米特的速度，是可以甩開它逃出來的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"위험한 유인 작전은 나 혼자 맡는 거 아니었어?","JPN":"危険な誘導作戦は私一人でやるんじゃなかったの？","ENG":"Wasn't it going to be just me luring that monster?","TWN":"危險的誘導行動不是我一個人負責的嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"목숨빚 계산하기 싫다는데 각출해야지.","JPN":"借りを計算したくないと言うから、割り勘にするしかないだろう。","ENG":"We're going together since you don't want me to think about owing you.","TWN":"既然不想計算性命債，那只好各出一半。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이쪽으로 온다!","JPN":"こっちに来る！","ENG":"It’s coming this way!!","TWN":"它過來了！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"가자, 허밋!","JPN":"行くぞ、ハーミット！","ENG":"Giddy up, Hermit!","TWN":"走吧，赫米特！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"뭐지? 저 괴물, 어디로 가는 거야?","JPN":"何だ？　あの化け物、どこに行くんだ？","ENG":"Huh? Where's that monster going?","TWN":"是怎樣？那個怪物要去哪？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"당황하지 마! 지휘관님 계획대로야!","JPN":"慌てるな！　指揮官の計画どおりだ！","ENG":"Don't worry! It's all part of Commander's plan!","TWN":"別慌！這是指揮官的計畫！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"이 틈에 성유물을 회수해서 기차역으로 철수한다!","JPN":"この隙に聖遺物を回収して駅まで撤収する！","ENG":"Use this opportunity to retrieve the Holy Relic and retreat to the station!","TWN":"趁現在收回聖遺物，再撤到車站！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"한나 씨! 서둘러 움직이죠!","JPN":"ハンナさん！　急ぎましょう！","ENG":"Miss Anderson! Let's move!","TWN":"漢娜！趕緊行動！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아, 네!","JPN":"あっ、はい！","ENG":"Oh, o-okay!","TWN":"喔，好！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"저어… 래시포드 씨, 사실 아까 말씀드리지 못한 게 있어요.","JPN":"あのぉ……ラッシュフォードさん、実はさっき言えなかったことがあるんです。","ENG":"Um... Miss Rashford? There's something that I haven't told you yet.","TWN":"那個…雷斯福特，其實我剛才有件事沒跟你說。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네? 하필 이런 상황에?","JPN":"はい？　よりによってこんな状況でですか？","ENG":"Huh? Can't it wait?","TWN":"嗯？偏偏挑這種時候？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아셔야 할 것 같아서요. 총사대의 시신들에서 이상한 점을 발견했거든요.","JPN":"知っておくべきだと思って。銃士隊の死体からおかしな点を発見したんです。","ENG":"I thought you should know. There was something odd about the corpses of those soldiers.","TWN":"我覺得你應該要知道，我在射擊隊的屍體上發現可疑之處。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"그 사람들, 대부분 침식체에 당한 게 아니라…….","JPN":"あの人たち、ほとんどが侵食体にやられたんじゃなくて……","ENG":"Most of them didn't die to a C.O., and...","TWN":"他們大部分都不是被侵蝕體殺掉的…"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"총에 맞아 죽은 게 분명해요.","JPN":"明らかに銃に撃たれて死んでいます。","ENG":"I'm certain they were shot to death.","TWN":"很明顯是中槍身亡的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그럼…… 성유물을 노리는 자들이 인간이었단 겁니까? 왜 진작 말하지 않았죠?","JPN":"では……聖遺物を狙った者は人間だったということですか？　どうして早く話さなかったんですか？","ENG":"Then what you're saying is... that whoever was after the Holy Relic was human? Why didn't you say anything sooner?","TWN":"意思是……覬覦聖遺物的是人類嗎？你怎麼不早說？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"함부로 말을 꺼내면 저랑 장교님까지 위험해질 것 같았어요.","JPN":"むやみに話せば、私と将校まで危険になるかもしれないと思って。","ENG":"I was afraid that if I said that in front of everyone, it would put us in a dangerous position.","TWN":"我怕隨口說出來的話，我和你也會有危險。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어쩌면 부대 내에 배신자가 있을지도 모르니까요.","JPN":"もしかしたら部隊の中に裏切り者がいるかもしれないじゃないですか。","ENG":"We can't be too sure if there is a traitor among us.","TWN":"說不定部隊裡有叛徒。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"성유물은 여길 떠날 때까지 수비대 손에 맡기지 않는 편이 좋겠어요.","JPN":"聖遺物はここを離れるまで守備隊に預けない方が良さそうですよ。","ENG":"So I don't think it's a good idea to leave the Holy Relic in the hands of the Border Guards until we leave.","TWN":"在離開這裡之前，最好不要將聖遺物交給護衛隊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"장교님! 이쪽입니다!","JPN":"将校！　こちらです！","ENG":"Officer! This way!","TWN":"軍官！這邊！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……알겠다. 바로 따라가지.","JPN":"……わかった。すぐ行く。","ENG":"...All right. I'm right behind you.","TWN":"……好，馬上過去。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이 얘기는 나중에 하도록 하죠. 지금은 여길 벗어나는 게 우선입니다.","JPN":"この話はまた後でしましょう。今はここから出るのが先決です。","ENG":"We'll talk more about this later. Right now, our priority is getting out of here.","TWN":"這件事之後再說吧，現在最重要的是離開這裡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"Y-yes, ma'am!","TWN":"喔，好的！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아직 멀었어?","JPN":"まだなの？","ENG":"How much further?","TWN":"還沒嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"참아. 조금 더 깊숙이 유인해야 돼.","JPN":"もう少し我慢しろ。もっと深いところまで追い込まないと。","ENG":"Hold on. We just need to go a little bit deeper.","TWN":"忍耐，要再往更裡面一點。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"방금 그게 마지막 화살이야. 놈이 부대원들에게 향할지도 몰라.","JPN":"矢はさっきのが最後よ。やつが部隊員のところに向かうかもしれない。","ENG":"That was the last of my arrows. It might go after the others now.","TWN":"剛才那是最後一支箭，它很可能會轉向攻擊隊員。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고삐를 잡아. 보직 변경이다.","JPN":"手綱を取れ。役割を変えよう。","ENG":"Grab the reins. I'll get its attention this time.","TWN":"抓著繮繩，計畫改變。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"왜 갑자기 거꾸로 앉아? 승마 묘기로 시선 끌 생각이야?","JPN":"なんでいきなり逆に座るの？　乗馬の技で目を引くつもり？","ENG":"Why are you sitting backwards? Are you trying to get its attention with your horseback riding tricks?","TWN":"幹嘛突然反過來坐？你想用高超的馬術吸引它嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"불편하다면 자리를 바꿀 수도 있다.","JPN":"都合が悪いなら席を変えることもできるが。","ENG":"If you feel uncomfortable, we can switch places.","TWN":"覺得不方便的話，我可以跟你換位置。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다만 그 과정에서 내가 미끄러져 낙마할 가능성은 매우 높다고 해 두지.","JPN":"ただ、その過程で私が滑って落馬する可能性が極めて高いということを伝えておこう。","ENG":"But my chances of slipping and falling off would be highly likely.","TWN":"不過在換位置時，我很可能會跌下馬。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"됐으니까 사격에나 집중해.","JPN":"いいから射撃に集中して。","ENG":"Then forget about it, and focus on shooting that thing.","TWN":"就這樣吧，你專心開你的槍。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"놈이 점점 빨라지고 있어. 이대로는 따라잡힐 거야.","JPN":"あいつ、段々速くなってきているよ。このままじゃ追いつかれる。","ENG":"It's gaining on us. It'll be right behind us at this rate...!","TWN":"它的速度越來越快，再這樣下去會被追上的。"},"stage":{"bg":"SKY","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…와트! 지금이다!","JPN":"……ワット！　今だ！","ENG":"Watt! NOW!","TWN":"…華特！就是現在！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"무너뜨려!","JPN":"崩せ！","ENG":"Make it crumble!","TWN":"推倒！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>지켜야…… 해.</color>","JPN":"<color=#ff3636>守ら……なければ。</color>","ENG":"<color=#ff3636>Must... Protect...</color>","TWN":"<color=#ff3636>要……保護…</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>그걸…… 가져 가선…… 안돼.</color>","JPN":"<color=#ff3636>それを……持って行っては……いけない。</color>","ENG":"<color=#ff3636>You... mustn't... take it...</color>","TWN":"<color=#ff3636>不可……以把它……拿走。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"……리안!","JPN":"……リアン！","ENG":"–rian!","TWN":"……里安！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"큐리안! 내 손 잡아!","JPN":"キュリアン！　手を取って！","ENG":"Curian! Grab my hand!","TWN":"庫里安！抓住我的手！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"헉…! 허억…!","JPN":"はぁ……！　はぁ……！","ENG":"*Huff...!* *Huff...!*","TWN":"呼…！呼呼…！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지난 번엔 암반을 부수더니 이제는 광산이네. 다음엔 산이라도 날려버릴 셈이지?","JPN":"この前は岩を砕いたかと思えば、今度は鉱山ね。次は山でも吹き飛ばすつもり？","ENG":"First it was the ground, now it's a mine. What are you going to blow up next? A mountain?","TWN":"上次是炸岩石，現在炸礦場，你下次是不是打算把山炸掉？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"허밋은…… 어디에 있지?","JPN":"ハーミットは……どこだ？","ENG":"Hermit... Where is he?","TWN":"赫米特……在哪裡？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HORSE_BORDER_NULL_NAMED","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_STEAM"},{"id":"L50_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"멀쩡히 잘 빠져나왔어. 걱정은 본인의 팔에나 해.","JPN":"無事抜け出たよ。自分の腕でも心配したらどう？","ENG":"We got out unscathed. Just worry about your arm, okay?","TWN":"它沒事，你擔心你自己的手臂吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"큭…! 뼈가 부러진 건가?","JPN":"くっ……！　骨が折れたのか？","ENG":"Kgh...! Is it broken?","TWN":"咳…！我骨折了嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"떨어지는 바위에 부딪쳤어.","JPN":"落ちてくる岩に当たっただけ。","ENG":"You got hit by one of the falling boulders.","TWN":"你剛才被掉落的石頭砸到。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"뭐가 됐든 저 낭떠러지 아래 파묻히는 것보다는 낫겠지만.","JPN":"どうであれ、あの崖の下に埋められるよりはましだね。","ENG":"Anyway, a broken arm is better than getting buried alive.","TWN":"總之怎樣都比埋在那個懸崖下好。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……성공한 건가?","JPN":"……成功したのか？","ENG":"Did it work...?","TWN":"……成功了嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"죽지는 않았으니 언제 다시 기어나올지 몰라.","JPN":"死んではいないから、いつまた這い出てくるかわからない。","ENG":"It's not dead, so we can't know when it'll crawl back out.","TWN":"它還沒死，不知道什麼時候會再爬上來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"합류지점으로 가자. 다들 기다리고 있을 거야.","JPN":"合流地点に行こう。みんな待ってるはずよ。","ENG":"Let's head to the rendezvous point. The troops will be waiting for us there.","TWN":"先去跟大家會合吧，他們都在等我們。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"대장님! 지휘관님! 여깁니다! 여기!","JPN":"隊長！　指揮官！　こっちです！　こっち！","ENG":"Captain! Commander! Over here!","TWN":"隊長！指揮官！這裡！這裡！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이런 세상에! 정말 무사하셨군요! 흙먼지가 솟구칠 때는 어떻게 되나 싶었는데!","JPN":"なんと！　本当に無事だったんですね！　土煙が上がった時にはどうなることかと思いましたが！","ENG":"My god! You're both alive! I was worried you didn't make it out!","TWN":"我的天！你真的沒事！剛炸得亂七八糟的時候，我還很擔心你不知道會怎樣呢！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"성유물은? 어떻게 됐지?","JPN":"聖遺物は？　どうなった？","ENG":"The Holy Relic... What happened to it?","TWN":"聖遺物呢？怎麼樣？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"내가 자기 소임을 방기할 만큼 무책임한 사람으로 보였나?","JPN":"私が自分の任務を放棄するほど無責任な人間に見えたか？","ENG":"Did you really believe I was irresponsible enough to ignore my responsibilities?","TWN":"你覺得我是那種不盡責的人嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"걱정 마. 무사히 회수했다.","JPN":"心配するな。無事回収した。","ENG":"Don't worry. We got it back in one piece.","TWN":"放心吧，已經安全回收。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래……. 다행이군. 정말 다행이야.","JPN":"そうか……よかったな。本当によかった。","ENG":"I see... That's such a relief.","TWN":"是嗎……那就好，那就好。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"전대원, 주목.","JPN":"総員、注目。","ENG":"All right. Attention everyone.","TWN":"大家注意，"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"모두 잘 살아남아 줬다.","JPN":"みんな、よく生き残ってくれた。","ENG":"Excellent work out there.","TWN":"很好，大家都有活下來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……이제 집으로 돌아가자.","JPN":"……もう家に帰ろう。","ENG":"Now... let's go home.","TWN":"……我們現在回家吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};